import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import './index.css';

console.log('El Nexo Digital: Iniciando aplicación...');

const rootElement = document.getElementById('root');

if (!rootElement) {
  console.error("ERROR CRÍTICO: No se encontró el elemento raíz 'root'.");
  throw new Error("Could not find root element to mount to");
}

interface ErrorBoundaryProps {
  children: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("Error capturado por Boundary:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '20px', textAlign: 'center', fontFamily: 'monospace', color: '#333' }}>
          <h1>Algo salió mal 😔</h1>
          <p>Por favor, recarga la página. Si el error persiste, verifica la consola.</p>
          <div style={{ marginTop: '20px', padding: '10px', background: '#f8d7da', color: '#721c24', borderRadius: '5px', overflow: 'auto', textAlign: 'left' }}>
            <pre style={{ whiteSpace: 'pre-wrap', fontSize: '12px' }}>
              {this.state.error?.toString()}
            </pre>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

try {
    const root = createRoot(rootElement);
    root.render(
      <React.StrictMode>
        <ErrorBoundary>
            <App />
        </ErrorBoundary>
      </React.StrictMode>
    );
} catch (e) {
    console.error("Error al montar React:", e);
    rootElement.innerHTML = `<div style="padding:20px;color:red;font-family:monospace"><h1>Error Crítico de Montaje</h1><p>Verifica la consola para más detalles.</p><pre>${e}</pre></div>`;
}

