  errorInfo: React.ErrorInfo | null;
}

// Componente Error Boundary para capturar fallos de renderizado
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error, errorInfo: null };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("Uncaught error in React component tree:", error, errorInfo);
    this.setState({ errorInfo });
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-[#fdfaf4] text-stone-800 p-8 font-mono">
          <div className="max-w-2xl w-full bg-white p-8 rounded-lg shadow-xl border border-stone-300">
            <h1 className="text-3xl font-bold mb-4 text-red-600">Algo salió mal.</h1>
            <p className="mb-4 text-lg">La aplicación ha encontrado un error inesperado.</p>

            <div className="bg-stone-100 p-4 rounded border border-stone-200 overflow-auto max-h-64 mb-6">
              <p className="font-bold text-red-800 mb-2">{this.state.error?.toString()}</p>
              <pre className="text-xs text-stone-600 whitespace-pre-wrap">
                {this.state.errorInfo?.componentStack}
              </pre>
            </div>

            <button 
              onClick={() => window.location.reload()}
              className="px-6 py-3 bg-stone-800 text-white rounded hover:bg-black transition-colors font-bold"
            >
              Recargar Aplicación
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

// Montaje seguro de la aplicación
try {
  const root = createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <ErrorBoundary>
        <App />
      </ErrorBoundary>
    </React.StrictMode>
  );
  console.log('El Nexo Digital: Aplicación montada correctamente.');
} catch (e) {
  console.error("Error fatal al montar React:", e);
  rootElement.innerHTML = `<div style="padding:20px; text-align:center;"><h1>Error de Inicio</h1><p>Verifica la consola para más detalles.</p></div>`;
}

