    </React.StrictMode>
  );
} else {
  console.error("No se encontró el elemento #root en el DOM.");
}

import React, { useState, useEffect, useRef, lazy, Suspense } from 'react';
import type { VideoPodcast, HeaderControls, StickyNote } from './types.ts';
import Header from './components/Header.tsx';
import LoadingSpinner from './components/LoadingSpinner.tsx';

// Componentes con carga diferida para no bloquear el inicio
const Magazine = lazy(() => import('./components/Magazine.tsx'));
const Library = lazy(() => import('./components/Library.tsx'));
const PodcastModal = lazy(() => import('./components/PodcastModal.tsx'));
const ProtectedContentModal = lazy(() => import('./components/ProtectedContentModal.tsx'));
const StickyNoteModal = lazy(() => import('./components/StickyNoteModal.tsx'));
const AdminNotesModal = lazy(() => import('./components/AdminNotesModal.tsx'));
const StickyNotesContainer = lazy(() => import('./components/StickyNotesContainer.tsx'));
const AdminAuthModal = lazy(() => import('./components/AdminAuthModal.tsx'));

const NOTES_KEY = 'elNexoDigitalAdminNotes';
const THEME_KEY = 'elNexoDigitalTheme';

const App: React.FC = () => {
  const [view, setView] = useState<'magazine' | 'library'>('magazine');
  const [dailyPodcast, setDailyPodcast] = useState<VideoPodcast | null>(null);
  const [modals, setModals] = useState({
    podcast: false,
    protected: false,
    note: false,
    admin: false,
    auth: false
  });

  const [isDarkMode, setIsDarkMode] = useState(() => localStorage.getItem(THEME_KEY) === 'dark');
  const [notes, setNotes] = useState<StickyNote[]>(() => {
    try {
      return JSON.parse(localStorage.getItem(NOTES_KEY) || '[]');
    } catch {
      return [];
    }
  });

  const [isAdmin, setIsAdmin] = useState(false);
  const headerRef = useRef<HeaderControls>(null);
  const wasPlaying = useRef(false);

  useEffect(() => {
    document.body.classList.toggle('dark', isDarkMode);
    localStorage.setItem(THEME_KEY, isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  useEffect(() => {
    import('./data/podcasts.ts').then(m => {
      if (m.VIDEO_PODCASTS.length > 0) {
        setDailyPodcast(m.VIDEO_PODCASTS[Math.floor(Math.random() * m.VIDEO_PODCASTS.length)]);
      }
    }).catch(err => console.error("Error cargando podcasts:", err));
  }, []);

  useEffect(() => {
    localStorage.setItem(NOTES_KEY, JSON.stringify(notes));
  }, [notes]);

  const toggleModal = (key: keyof typeof modals, open: boolean) => {
    if (key === 'podcast' || key === 'protected') {
      if (open) {
        wasPlaying.current = headerRef.current?.getIsPlayingState() || false;
        headerRef.current?.pauseRadio();
      } else if (wasPlaying.current) {
        headerRef.current?.playRadio();
      }
    }
    setModals(prev => ({ ...prev, [key]: open }));
  };

  const handleAdminAuth = () => isAdmin ? toggleModal('admin', true) : toggleModal('auth', true);

  const onLogin = (pass: string) => {
    if (pass === 'sauce') {
      setIsAdmin(true);
      toggleModal('auth', false);
      toggleModal('admin', true);
      return true;
    }
    return false;
  };

  const addNote = (data: { name: string; text: string }) => {
    const colors = ['#ffc', '#cfc', '#ccf', '#fcc', '#cff', '#ffb3ba'];
    const newNote: StickyNote = {
      id: `n_${Date.now()}`,
      name: data.name || 'Anónimo',
      text: data.text,
      color: colors[Math.floor(Math.random() * colors.length)],
      position: { x: Math.random() * 80 + 10, y: Math.random() * 80 + 10 },
      rotation: Math.random() * 30 - 15,
    };
    setNotes(prev => [...prev, newNote]);
    toggleModal('note', false);
  };

  return (
    <div className="min-h-screen relative overflow-x-hidden">
      <Header 
        ref={headerRef}
        isPodcastModalOpen={modals.podcast}
        onPodcastButtonClick={() => toggleModal('podcast', true)}
        showPodcastButton={!!dailyPodcast}
        onProtectedButtonClick={() => toggleModal('protected', true)}
        onStickyNoteButtonClick={() => toggleModal('note', true)}
        onLibraryButtonClick={() => setView('library')}
        notesCount={notes.length}
        onAdminAuthRequest={handleAdminAuth}
        isDarkMode={isDarkMode}
        onToggleDarkMode={() => setIsDarkMode(!isDarkMode)}
      />

      <main className="container mx-auto px-4 py-8">
        <Suspense fallback={<LoadingSpinner />}>
          {view === 'magazine' ? <Magazine /> : <Library onBackToMagazine={() => setView('magazine')} />}
        </Suspense>
      </main>

      {/* Modales cargados bajo demanda */}
      <Suspense fallback={null}>
        {modals.podcast && dailyPodcast && <PodcastModal isOpen={modals.podcast} onClose={() => toggleModal('podcast', false)} podcast={dailyPodcast} />}
        {modals.protected && <ProtectedContentModal isOpen={modals.protected} onClose={() => toggleModal('protected', false)} />}
        {modals.note && <StickyNoteModal isOpen={modals.note} onClose={() => toggleModal('note', false)} onAddNote={addNote} />}
        {modals.auth && <AdminAuthModal isOpen={modals.auth} onClose={() => toggleModal('auth', false)} onLogin={onLogin} />}
        {modals.admin && <AdminNotesModal isOpen={modals.admin} onClose={() => toggleModal('admin', false)} notes={notes} setNotes={setNotes} />}
        <StickyNotesContainer notes={notes} isNotesAdmin={isAdmin} onAdminAuthRequest={handleAdminAuth} />
      </Suspense>
    </div>
  );
};

export default App;

