import React, { useState, useEffect, useRef, Suspense } from 'react';
import type { VideoPodcast, HeaderControls, StickyNote } from './types.ts';
import Header from './components/Header.tsx';
import LoadingSpinner from './components/LoadingSpinner.tsx';
import Magazine from './components/Magazine.tsx';
import Library from './components/Library.tsx';
import StickyNotesContainer from './components/StickyNotesContainer.tsx';

// Estos se mantienen como carga normal para evitar problemas de inicio
const NOTES_KEY = 'elNexoDigitalAdminNotes';
const THEME_KEY = 'elNexoDigitalTheme';

const App: React.FC = () => {
  const [view, setView] = useState<'magazine' | 'library'>('magazine');
  const [dailyPodcast, setDailyPodcast] = useState<VideoPodcast | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof localStorage !== 'undefined') {
      return localStorage.getItem(THEME_KEY) === 'dark';
    }
    return false;
  });

  const [notes, setNotes] = useState<StickyNote[]>([]);
  const [isAdmin, setIsAdmin] = useState(false);
  const headerRef = useRef<HeaderControls>(null);

  useEffect(() => {
    document.body.classList.toggle('dark', isDarkMode);
    localStorage.setItem(THEME_KEY, isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  useEffect(() => {
    // Carga de notas segura
    try {
      const saved = localStorage.getItem(NOTES_KEY);
      if (saved) setNotes(JSON.parse(saved));
    } catch (e) {
      console.warn("Error cargando notas", e);
    }

    // Carga de podcasts
    import('./data/podcasts.ts').then(m => {
      if (m.VIDEO_PODCASTS && m.VIDEO_PODCASTS.length > 0) {
        setDailyPodcast(m.VIDEO_PODCASTS[Math.floor(Math.random() * m.VIDEO_PODCASTS.length)]);
      }
    }).catch(err => console.error("Error cargando podcasts:", err));
  }, []);

  useEffect(() => {
    if (notes.length > 0) {
      localStorage.setItem(NOTES_KEY, JSON.stringify(notes));
    }
  }, [notes]);

  const handleAdminAuth = () => {
    const pass = prompt("Acceso Administrador:");
    if (pass === 'sauce') {
      setIsAdmin(true);
      alert("Acceso concedido");
    } else if (pass !== null) {
      alert("Clave incorrecta");
    }
  };

  return (
    <div className="min-h-screen relative">
      <Header 
        ref={headerRef}
        isPodcastModalOpen={false}
        onPodcastButtonClick={() => {}} // Se simplifica para test de inicio
        showPodcastButton={!!dailyPodcast}
        onProtectedButtonClick={() => {}} 
        onStickyNoteButtonClick={() => {}}
        onLibraryButtonClick={() => setView('library')}
        notesCount={notes.length}
        onAdminAuthRequest={handleAdminAuth}
        isDarkMode={isDarkMode}
        onToggleDarkMode={() => setIsDarkMode(!isDarkMode)}
      />

      <main className="container mx-auto px-4 py-8">
        {view === 'magazine' ? <Magazine /> : <Library onBackToMagazine={() => setView('magazine')} />}
      </main>

      <StickyNotesContainer 
        notes={notes} 
        isNotesAdmin={isAdmin} 
        onAdminAuthRequest={handleAdminAuth} 
      />
    </div>
  );
};

export default App;

