      } catch (e) {
        console.error("Error cargando música:", e);
      } finally {
        setIsLoading(false);
      }
    };
    init();
  }, []);

  const togglePlay = () => {
    if (isLoading || !audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
