  box-shadow: inset 0 -2px 0 rgba(0,0,0,0.5);
  font-family: 'Courier Prime', monospace;
}

@media (max-width: 768px) {
  .listener-counter {
    top: 10px;
    right: 10px;
    padding: 6px 12px;
    gap: 8px;
    scale: 0.85;
  }
}

/* Other UI Helpers */
.admin-notes-icon { position: absolute; top: 90px; left: 15px; z-index: 21; width: 50px; cursor: pointer; transition: transform 0.2s ease-in-out; filter: drop-shadow(0 4px 6px rgba(0,0,0,0.2)); }
.gift-ribbon-wrapper { width: 150px; height: 150px; overflow: hidden; position: absolute; top: 0; left: 0; z-index: 30; pointer-events: none; }
.gift-ribbon { position: absolute; display: block; width: 225px; padding: 10px 0; background-color: #dc2626; color: #fff; font: 700 10px/1 'Courier Prime', monospace; text-transform: uppercase; text-align: center; left: -50px; top: 35px; transform: rotate(-45deg); letter-spacing: 1px; }
